import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

// Resolved PulseBoard account with defaults applied
export interface ResolvedPulseBoardAccount {
  accountId: string;
  boardUrl: string;
  apiToken: string;
  username: string;
  configured: boolean;
}

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: CHANNEL_ID,
    meta: {
      // Spread meta from registry (returns undefined for unregistered channels; safe to spread)
      ...getChatChannelMeta(CHANNEL_ID as Parameters<typeof getChatChannelMeta>[0]),
      id: CHANNEL_ID,
      label: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Connect to PulseBoard bulletin messaging.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: {
      configPrefixes: ["channels.pulseboard"],
    },
    config: {
      listAccountIds: (_cfg) => [],
      resolveAccount: (_cfg, accountId) => ({
        accountId: accountId ?? "default",
        boardUrl: "",
        apiToken: "",
        username: "",
        configured: false,
      }),
      isConfigured: (account) => account.configured,
      describeAccount: (account) => ({
        accountId: account.accountId,
        name: account.username || undefined,
        enabled: true,
        configured: account.configured,
      }),
    },
    setup: {
      applyAccountConfig: ({ cfg }) => {
        // Stub: return config unchanged
        return cfg;
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        ctx.log?.info(
          `[${account.accountId}] connecting to PulseBoard at ${account.boardUrl || "(no url configured)"}`,
        );

        // Stub: no real connection; return a no-op cleanup
        return {
          stop: () => {
            ctx.log?.info(`[${account.accountId}] PulseBoard connection stopped`);
          },
        };
      },
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, text, accountId }) => {
      const aid = accountId ?? "default";
      const messageId = `pb-${aid}-${Date.now()}`;
      // Stub: log and return a synthetic delivery result
      return attachChannelToResult(CHANNEL_ID, {
        to,
        messageId,
      });
    },
  },
});

